// === CẤU HÌNH ===
const SUPABASE_URL = 'https://fpesidoqwxyyutgvalsp.supabase.co';
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImZwZXNpZG9xd3h5eXV0Z3ZhbHNwIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3NTY3NDkzNywiZXhwIjoyMDkxMjUwOTM3fQ.X9s9a_rSNefhdd7UEsTulNB1xct4JK_QZe2UzIubPg8';
const CHAT_ID = '-5163098733';

// === TÍNH NGÀY (SGT = UTC+7) ===
const now = new Date();
const SGT_OFFSET = 7 * 60 * 60 * 1000;
const sgtNow = new Date(now.getTime() + SGT_OFFSET);
const sgtDateStr = sgtNow.toISOString().split('T')[0]; // YYYY-MM-DD
const startDate = new Date(sgtDateStr + 'T00:00:00+07:00').toISOString();
const endDate = now.toISOString();

const headers = {
  'apikey': SUPABASE_KEY,
  'Authorization': `Bearer ${SUPABASE_KEY}`,
  'Content-Type': 'application/json'
};

// === QUERY 1: Ứng viên mới trong ngày ===
const candidatesResp = await $helpers.httpRequest({
  method: 'GET',
  url: `${SUPABASE_URL}/rest/v1/candidates?select=id_ld,full_name,order_id,interview_status,agent_id&synced_at=gte.${encodeURIComponent(startDate)}&synced_at=lt.${encodeURIComponent(endDate)}&order=synced_at.asc`,
  headers
});
const candidates = Array.isArray(candidatesResp) ? candidatesResp : [];

// === QUERY 2: Đơn hàng còn thiếu lao động ===
const ordersResp = await $helpers.httpRequest({
  method: 'GET',
  url: `${SUPABASE_URL}/rest/v1/orders?select=id,company_name,job_type,total_labor,labor_missing,status&labor_missing=gt.0&order=created_at.desc`,
  headers
});
const orders = Array.isArray(ordersResp) ? ordersResp : [];

// === FORMAT TIN NHẮN ===
// Định dạng ngày theo tiếng Việt: DD/MM/YYYY
const [yyyy, mm, dd] = sgtDateStr.split('-');
const dateDisplay = `${dd}/${mm}/${yyyy}`;

let text = `📊 *BÁO CÁO NGÀY ${dateDisplay}*\n`;
text += `━━━━━━━━━━━━━━━━━━\n\n`;

// --- Phần 1: Ứng viên mới ---
if (candidates.length === 0) {
  text += `🆕 *Ứng viên mới hôm nay:* Không có\n`;
} else {
  text += `🆕 *Ứng viên mới hôm nay: ${candidates.length} người*\n`;

  // Nhóm theo đơn hàng
  const byOrder = {};
  for (const c of candidates) {
    const key = c.order_id || 'Chưa phân đơn';
    if (!byOrder[key]) byOrder[key] = { pass: 0, fail: 0, pending: 0 };
    const status = (c.interview_status || '').toLowerCase();
    if (status === 'pass') byOrder[key].pass++;
    else if (status === 'fail') byOrder[key].fail++;
    else byOrder[key].pending++;
  }

  for (const [orderId, stats] of Object.entries(byOrder)) {
    const total = stats.pass + stats.fail + stats.pending;
    const parts = [];
    if (stats.pass > 0) parts.push(`✅ ${stats.pass} pass`);
    if (stats.fail > 0) parts.push(`❌ ${stats.fail} fail`);
    if (stats.pending > 0) parts.push(`⏳ ${stats.pending} chờ`);
    text += `  📦 ${orderId}: ${total} người — ${parts.join(', ') || '⏳ chờ duyệt'}\n`;
  }
}

text += `\n`;

// --- Phần 2: Đơn hàng đang tuyển ---
if (orders.length === 0) {
  text += `📋 *Đơn hàng:* Tất cả đã đủ lao động 🎉`;
} else {
  const totalMissing = orders.reduce((sum, o) => sum + (parseInt(o.labor_missing) || 0), 0);
  text += `📋 *Đơn hàng đang tuyển: ${orders.length} đơn — còn thiếu ${totalMissing} suất*\n`;

  const displayed = orders.slice(0, 8);
  for (const o of displayed) {
    text += `  • ${o.company_name} — ${o.job_type}\n    còn thiếu *${o.labor_missing}/${o.total_labor}* suất\n`;
  }
  if (orders.length > 8) {
    text += `  _...và ${orders.length - 8} đơn khác_\n`;
  }
}

return [{
  json: {
    text,
    chat_id: CHAT_ID
  }
}];
